$ErrorActionPreference = 'Stop'
$tmplPath = 'C:\Users\NGUYEN~1\AppData\Local\Temp\claude\C--Users-nguyentrungtin-Documents\e4e7fc64-d0ea-4294-aa6f-e1d12bb4feae\scratchpad\workflow.tmpl'
$outPath  = 'C:\Users\nguyentrungtin\Documents\SweetSaigon_DNA_Builder_v2.json'

$NOTIFY_START = @'
=🧬 Đang quét TOÀN BỘ kho ảnh thành phẩm để build Brand DNA + Thư viện Hiệu ứng (Effect Library)...
'@

$ANALYZE_PROMPT = @'
You are a senior brand art director analyzing ONE finished Sweet Saigon marketing image. Report ONLY what is visually observable in THIS image; do not assume brand-wide rules.

MOST IMPORTANT TASK: identify the SINGLE dominant creative DEVICE/EFFECT that makes this image distinctive — e.g. floating UI / album / music-player cards, product surrounded by themed props, surreal oversized product in a real place, editorial poster with big typography, liquid splash, levitation, double exposure, neon light-trails, etc. Describe it in a TRANSFERABLE, brand-agnostic way: describe the TECHNIQUE, never the specific songs/brands/props/text content.

Return RAW valid JSON only, no markdown fence, exactly this shape:
{"palette_hex":["#RRGGBB"],"lighting":"direction, hardness, contrast","mood":["adjectives"],"composition":"framing, angle, balance, negative space","background":"setting and backdrop","product_scale":"small|medium|large|giant|na","product_placement":"where the product sits in frame","product_staging":"how it is held / supported / hierarchy","human_presence":"none|hand|person","text_present":true,"fx":["splash, particles, glow, steam..."],"hero_device":"the ONE defining creative device, transferable and brand-agnostic","device_recipe":"step-by-step how to rebuild this device around a DIFFERENT product","device_physics":{"scale":"small|medium|large|giant","placement":"natural anchor for the product under this device","text_allowed":true,"person_present":"none|hand|person","floating_elements":["what floats / surrounds, generic"]},"confidence":0.0}
'@

$COLLECT_CODE = @'
// Gom và kiểm tra kết quả của từng ảnh trước khi tổng hợp DNA cuối.
const results = $input.all();
const files = $('List ALL DNA Files').all();

function responseText(j) {
  let v = j?.content ?? j?.message?.content ?? j?.text ?? j?.output ?? j?.choices?.[0]?.message?.content ?? '';
  if (Array.isArray(v)) v = v.map(x => x?.text ?? x?.content ?? '').join('');
  if (typeof v === 'object') v = JSON.stringify(v);
  return String(v || '');
}

function parseObject(raw) {
  const clean = String(raw).replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  try { return JSON.parse(clean); } catch (_) {}
  const first = clean.indexOf('{');
  const last = clean.lastIndexOf('}');
  if (first >= 0 && last > first) return JSON.parse(clean.slice(first, last + 1));
  throw new Error('Không tìm thấy JSON object hợp lệ');
}

const analyses = [];
const failures = [];
for (let i = 0; i < results.length; i++) {
  const file = files[i]?.json || {};
  const raw = responseText(results[i].json);
  try {
    const parsed = parseObject(raw);
    parsed._file_id = file.id || '';
    parsed._file_name = file.name || `image_${i + 1}`;
