// ===== Parse Pinterest -> ref_image_url (tolerant) =====
const ctx = $('Build Gen Context').first().json;
const html = String($input.first().json.data || $input.first().json.body || '');
const dec = s => s.replace(/&quot;/g,'"').replace(/&#x27;/g,"'").replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>');
let img='';
if (ctx.ref_pin_url) {
  const ms=[...html.matchAll(/<script[^>]+application\/ld\+json[^>]*>([\s\S]*?)<\/script>/g)];
  for (const m of ms){ try{ const j=JSON.parse(dec(m[1])); if(j.image){img=Array.isArray(j.image)?j.image[0]:j.image; break;} }catch(e){} }
  if(!img){ const og=html.match(/property="og:image"[^>]+content="([^"]+)"/); if(og) img=og[1]; }
}
return [{ json: { ...ctx, ref_image_url: img, ref_available: !!img } }];
