$PREP_GEMINI = @'
// Build 2 Gemini bodies @2K. Identity khoá cứng; PHYSICS động theo archetype; Ver1 sáng tạo cao, Ver2 bám ref ~50-60%.
const pa   = $('Parse Art Director').first().json;
const item = $input.first();
const refAvail = !!pa.ref_available && !!item.binary?.ref_image;
if (!item.binary?.product_image) throw new Error('Thiếu product_image binary');

const prodBuf = await this.helpers.getBinaryDataBuffer(0,'product_image');
const prodMime= item.binary.product_image.mimeType || 'image/png';
const prodB64 = prodBuf.toString('base64');
let refB64='', refMime='image/jpeg';
if (item.binary?.ref_image){ const rb=await this.helpers.getBinaryDataBuffer(0,'ref_image'); refMime=item.binary.ref_image.mimeType||'image/jpeg'; refB64=rb.toString('base64'); }

const AR = pa.aspect_ratio || '1:1';
const S = () => Math.floor(Math.random()*2147483647);
const gcfg = (seed) => ({ candidateCount:1, responseModalities:['TEXT','IMAGE'], seed, imageConfig:{ aspectRatio:AR, imageSize:'2K' } });

// ---- PHYSICS động ----
const phys = pa.product_physics || {};
const scale = String(phys.scale||'medium').toLowerCase();
const placement = phys.placement || 'natural, off-center (rule of thirds)';
const person = String(phys.person_present||'optional').toLowerCase();
const floating = Array.isArray(phys.floating_elements) ? phys.floating_elements.join(', ') : String(phys.floating_elements||'');
const textAllowed = (phys.text_allowed===true) || String(phys.text_allowed).toLowerCase()==='yes';

const scaleMap = {
  small:  'Scale the product SMALL (~15-30% of frame height) with generous negative space.',
  medium: 'Scale the product MEDIUM (~30-45% of frame height), balanced with breathing room.',
  large:  'Scale the product LARGE and dominant (~50-70% of frame height), never cropped.',
  giant:  'Scale the product as a GIANT surreal hero filling most of the frame, integrated realistically into the environment.'
};
const scaleTxt = scaleMap[scale] || scaleMap.medium;
const personMap = {
  none:     'No person; the product is supported by a surface or floats as the concept dictates.',
  hand:     'A real hand naturally holds or presents the product.',
  person:   'A joyful, life-loving young model (copyright-safe, NOT resembling anyone in the reference) enjoys the product with the drink and the music.',
  optional: 'Optionally a real hand or a joyful young model, whichever makes the composition natural.'
};
const personTxt = personMap[person] || personMap.optional;
const effectTxt = floating ? ('Reproduce the creative EFFECT around the product: '+floating+'. Keep the effect elements smaller than the product and orbiting/scattered around it, with depth and bokeh.') : 'Reproduce the concept effect tastefully around the product.';
const textRule = textAllowed
 ? 'You MAY render the concept UI / card / typographic elements as part of the effect; keep any text short, clean and legible — no gibberish, no unrelated watermark.'
 : 'NO text/letters/numbers/watermark anywhere except the product own printed label.';

const IDENTITY_LOCK =
`IDENTITY LOCK (appearance only): treat the product photo as a printed DECAL/STICKER you may SCALE, MOVE and slightly ROTATE as ONE unit, but must NOT repaint. Keep its cup silhouette, the exact printed logo, all label text, the drink colours and layers, toppings and ice EXACTLY as given — same pixels, only transformed. Never redraw a different cup, logo, label or drink.`;

const PHYS_BLOCK =
`PRODUCT PHYSICS (follow exactly): ${scaleTxt} Placement: ${placement}. ${personTxt}
${effectTxt}
Keep the product fully visible (never crop cup/lid/logo), tack-sharp, blended with the scene light direction, shadows, perspective and reflections.
${textRule}`;

const HARD_V1 =
`COMPOSITING TASK — build a FRESH, high-creativity, on-brand scene and composite the REAL product into it. Photo-compositing, not generating a new product.
IMAGE 1 = the finished product photo.
${IDENTITY_LOCK}
This is the BOLD, brand-forward version: reinterpret the creative device with high creativity and premium finish, clearly diverging from the reference while staying on brand.${refAvail ? `
IMAGE 2 = DEVICE EXEMPLAR: replicate ONLY its creative EFFECT/technique (${pa.resolved_archetype_name||'the effect'}). Its background, brand, products, text and people are IRRELEVANT — do NOT copy them.` : ''}
${PHYS_BLOCK}
Output aspect ratio ${AR}.`;

const HARD_V2_REF =
`COMPOSITE-INTO-REF (faithful ~50-60%) — keep about half of the reference creative device, staging, composition and mood, but SWAP in our product and refresh the background to be on-brand.
IMAGE 1 = REFERENCE: preserve its signature EFFECT/device and general layout and mood (~50-60%). Remove its original hero product and any of its brand text/watermark. Replace its background with a fresh on-brand setting per the scene brief.
IMAGE 2 = the finished product photo.
${IDENTITY_LOCK}
${PHYS_BLOCK}
Output aspect ratio ${AR}.`;

const HARD_V2_NOREF =
`COMPOSITING TASK — build a SECOND, distinct on-brand scene (different angle and mood from Ver 1) and composite the REAL product into it.
IMAGE 1 = the finished product photo.
${IDENTITY_LOCK}
${PHYS_BLOCK}
Output aspect ratio ${AR}.`;

const baseNeg = 'redrawn product, modified label, different cup, deformed cup, changed drink color, extra fingers, AI artifacts, plastic look, oversaturated, low detail';
const textNeg = textAllowed ? '' : ', text overlay, typography, watermark, gibberish text';

const v1text = HARD_V1 + '\n\n=== SCENE BRIEF (Ver1 — creative) ===\n' + (pa.ver1_prompt_en||'') + '\n\n[NEGATIVE] ' + (pa.ver1_negative||'') + textNeg + ', ' + baseNeg;
let v1parts = [ { text:v1text }, { inline_data:{ mime_type:prodMime, data:prodB64 } } ];
if (refAvail) v1parts.push({ inline_data:{ mime_type:refMime, data:refB64 } });

let v2text, v2parts;
if (refAvail) {
  v2text = HARD_V2_REF + '\n\n=== SCENE BRIEF (Ver2 — faithful) ===\n' + (pa.ver2_prompt_en||'') + '\n\n[NEGATIVE] ' + (pa.ver2_negative||'') + textNeg + ', ' + baseNeg + ', ignoring the reference effect, plain copy of the reference background';
  v2parts = [ { text:v2text }, { inline_data:{ mime_type:refMime, data:refB64 } }, { inline_data:{ mime_type:prodMime, data:prodB64 } } ];
} else {
  v2text = HARD_V2_NOREF + '\n\n=== SCENE BRIEF (variant B) ===\n' + (pa.ver2_prompt_en||'') + '\n\n[NEGATIVE] ' + (pa.ver2_negative||'') + textNeg + ', ' + baseNeg;
  v2parts = [ { text:v2text }, { inline_data:{ mime_type:prodMime, data:prodB64 } } ];
}

return [{ json: {
  gemini_body_ver1: { contents:[{ role:'user', parts:v1parts }], generationConfig:gcfg(S()) },
  gemini_body_ver2: { contents:[{ role:'user', parts:v2parts }], generationConfig:gcfg(S()) },
  ref_available: refAvail
}}];
